const ICON_NAME_SET = new Set<string>(LUCIDE_ICON_NAMES)

export function isLucideIconName(value: string): value is LucideIconName {
  return ICON_NAME_SET.has(value)
}

export function formatLucideIconLabel(name: string): string {
  return name.replace(/([a-z0-9])([A-Z])/g, "$1 $2").replace(/([A-Z])([A-Z][a-z])/g, "$1 $2")
}
